with detail = 0 {
    with link = "line.nl.DHA" {
        let da = path("d0.nl.dha");

        with railway = :first :double :cat:dc15 :pax {
            track(:single, da[:den, :sag]);
            track(da[:sag, :uit.yh]);
            track(da[:uit.yh, :zaa]);
            track(da[:sin.yz, :ams]);
        }
    }

    with link = "line.nl.ZSG" {
        let zs = path("d0.nl.zsg");

        with railway = :first :double :cat:dc15 :pax {
            track(zs[:zaa, :asl.yr]);
            track(zs[:asl.yr, :sin.yz]);
        }
    }
}

